content.query:
// Operator MUST replace $(SERVICE_ACCOUNT_UPN) with their service account UPN
// from the ARM deployment parameter — this workbook is a TEMPLATE; the
// XdrOps-ServiceAccountAnomalousSignIn analytic rule uses the same parameter.
let serviceAccountUpn = '$(SERVICE_ACCOUNT_UPN)';
SigninLogs
| where TimeGenerated {TimeRange}
| where UserPrincipalName =~ serviceAccountUpn
| extend Country = tostring(LocationDetails.countryOrRegion)
| summarize SignInCount = count(),
            UniqueIPs = dcount(IPAddress),
            UniqueCountries = dcount(Country),
            FailedSignIns = countif(ResultType != 0)
            by bin(TimeGenerated, 1h)
| render timechart
